import React from 'react';
import Button from './Button/Button';
import s from './Content.module.css'
import Massages from './Massages/Massages';
import Textarea from './textarea/Textarea';

const Content = () => {

let posts=[
  {id: 1, post:"fuck u", likesCount : 5},
  {id: 1, post:"good luck", likesCount : 23},
  {id: 1, post:"nice try", likesCount : 13},
  {id: 1, post:"maybe", likesCount : 76},
  {id: 1, post:"real talk", likesCount : 29}
]
let postsElements =
posts.map (p =><Massages massage = {p.post} likesCount = {p.likesCount}/>)

  return (
    <div>
      <div className={s.text}>
        <div> <h2>Content</h2> </div> 
        <Textarea/>
        <Button/>
        {postsElements}
      </div>
    </div>
  )

}
export default Content;
